#[derive(Clone, PartialEq)]
pub enum RiskLevel {
    Low,
    Medium,
    High,
}

pub struct ModelVote {
    pub model_id: String,
    pub approve: bool,
}

pub struct ConsensusGate {
    pub required_votes: usize,
    pub votes: Vec<ModelVote>,
}

impl ConsensusGate {
    pub fn new(required_votes: usize) -> Self {
        Self {
            required_votes,
            votes: Vec::new(),
        }
    }

    pub fn cast_vote(&mut self, model_id: String, approve: bool) {
        self.votes.push(ModelVote { model_id, approve });
    }

    pub fn quorum_reached(&self) -> bool {
        self.votes.iter().filter(|v| v.approve).count() >= self.required_votes
    }
}

pub fn assess_risk(
    file_count: usize,
    touches_security: bool,
    touches_public_api: bool,
) -> RiskLevel {
    if file_count > 8 || touches_security || touches_public_api {
        RiskLevel::High
    } else if file_count > 4 {
        RiskLevel::Medium
    } else {
        RiskLevel::Low
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_quorum_not_reached_with_one_vote() {
        let mut gate = ConsensusGate::new(2);
        gate.cast_vote("model-a".to_string(), true);
        assert!(!gate.quorum_reached());
    }

    #[test]
    fn test_quorum_reached_with_two_votes() {
        let mut gate = ConsensusGate::new(2);
        gate.cast_vote("model-a".to_string(), true);
        gate.cast_vote("model-b".to_string(), true);
        assert!(gate.quorum_reached());
    }

    #[test]
    fn test_assess_risk_high_on_large_diff() {
        assert!(matches!(assess_risk(9, false, false), RiskLevel::High));
    }
}

